typedef struct { int field; } my_struct_t;
function my_struct_t get_config(int sel);
  return my_struct_t'{field: sel};
endfunction
localparam my_struct_t CONFIG = get_config(1);

typedef struct { logic [31:0] val; } cfg_t;
function cfg_t mk_cfg(input int x);
  mk_cfg.val = x;
endfunction
localparam cfg_t C = mk_cfg(1);

typedef struct {
  int upper;
  struct packed { int quad; } nested;
} cfg_t;
function cfg_t gen_cfg(int s);
  gen_cfg.upper = s;
  gen_cfg.nested.quad = s;
endfunction
localparam cfg_t MY_CFG = gen_cfg(1);
